'use client';

import { useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { Settings, Lock, Trash2, Globe, Palette } from 'lucide-react';

export default function SettingsPage() {
  const { user, logout } = useAuth();
  const [oldPassword, setOldPassword] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);

  const handlePasswordChange = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');
    setSuccess('');
    try {
      const res = await fetch('http://localhost:5000/api/user/password', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ oldPassword, newPassword }),
        credentials: 'include'
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error);
      setSuccess("Password updated successfully");
      setOldPassword('');
      setNewPassword('');
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const handleDeleteAccount = async () => {
    try {
      await fetch('http://localhost:5000/api/user', { method: 'DELETE', credentials: 'include' });
      logout();
    } catch (err) {
      console.error(err);
    }
  };

  if (!user) return <div className="p-8 text-center text-gray-400">Please log in to access settings.</div>;

  return (
    <div className="container" style={{ paddingTop: '4rem', maxWidth: '800px' }}>
      <div className="flex items-center justify-between mb-12 px-2">
        <div>
          <h1 className="text-4xl font-bold tracking-tight text-white">Settings</h1>
          <p className="text-gray-500 mt-1">Manage your account security and preferences.</p>
        </div>
        <div className="p-3 bg-white/5 rounded-2xl border border-white/5">
          <Settings size={24} className="text-gray-400" />
        </div>
      </div>
      
      <div className="space-y-6">
        {/* Security Section */}
        <div className="bg-white/[0.03] border border-white/5 rounded-[32px] overflow-hidden">
          <div className="p-8 border-b border-white/5 flex items-center gap-4">
            <div className="p-2 bg-indigo-500/10 rounded-xl text-indigo-400">
              <Lock size={20} />
            </div>
            <h2 className="text-lg font-bold">Account Security</h2>
          </div>
          
          <div className="p-8">
            <form onSubmit={handlePasswordChange} className="space-y-6 max-w-md">
              {error && <div className="p-4 text-sm text-red-400 bg-red-400/5 border border-red-400/10 rounded-2xl">{error}</div>}
              {success && <div className="p-4 text-sm text-green-400 bg-green-400/5 border border-green-400/10 rounded-2xl">{success}</div>}
              
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-gray-500 uppercase tracking-widest ml-1">Current Password</label>
                <input 
                  type="password" placeholder="••••••••" required
                  className="w-full bg-black/50 border border-white/10 rounded-2xl px-5 py-3 text-white outline-none focus:ring-2 focus:ring-indigo-500/50 transition-all"
                  value={oldPassword} onChange={e => setOldPassword(e.target.value)}
                />
              </div>
              
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-gray-500 uppercase tracking-widest ml-1">New Password</label>
                <input 
                  type="password" placeholder="••••••••" required
                  className="w-full bg-black/50 border border-white/10 rounded-2xl px-5 py-3 text-white outline-none focus:ring-2 focus:ring-indigo-500/50 transition-all"
                  value={newPassword} onChange={e => setNewPassword(e.target.value)}
                />
              </div>

              <button 
                type="submit" disabled={isLoading}
                className="px-10 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl font-bold transition-all shadow-xl shadow-indigo-600/20 disabled:opacity-50"
              >
                {isLoading ? 'Processing...' : 'Update Password'}
              </button>
            </form>
          </div>
        </div>

        {/* Preferences Section */}
        <div className="bg-white/[0.03] border border-white/5 rounded-[32px] p-8 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="p-2 bg-pink-500/10 rounded-xl text-pink-400">
              <Globe size={20} />
            </div>
            <div>
              <h2 className="text-lg font-bold">Language</h2>
              <p className="text-sm text-gray-500">Choose your preferred interface language.</p>
            </div>
          </div>
          
          <select className="bg-black/50 border border-white/10 rounded-xl px-4 py-2 text-sm text-white outline-none focus:ring-2 focus:ring-pink-500/50">
            <option>English</option>
            <option>Spanish</option>
            <option>French</option>
          </select>
        </div>

        {/* Danger Zone Section */}
        <div className="bg-red-500/[0.02] border border-red-500/10 rounded-[32px] p-8 flex flex-col md:flex-row items-center justify-between gap-6">
          <div className="flex items-center gap-4">
            <div className="p-2 bg-red-500/10 rounded-xl text-red-500">
              <Trash2 size={20} />
            </div>
            <div>
              <h2 className="text-lg font-bold text-red-500">Danger Zone</h2>
              <p className="text-sm text-gray-500">This action is permanent and cannot be undone.</p>
            </div>
          </div>
          
          {showDeleteConfirm ? (
            <div className="flex items-center gap-3 animate-in zoom-in-95 duration-300">
              <button onClick={handleDeleteAccount} className="px-6 py-2.5 bg-red-600 hover:bg-red-700 text-white rounded-xl font-bold transition-all">
                Confirm
              </button>
              <button onClick={() => setShowDeleteConfirm(false)} className="px-6 py-2.5 bg-white/5 text-gray-400 rounded-xl font-bold">
                Cancel
              </button>
            </div>
          ) : (
            <button 
              onClick={() => setShowDeleteConfirm(true)}
              className="px-8 py-2.5 border border-red-500/20 text-red-500 hover:bg-red-500/10 rounded-xl font-bold transition-all"
            >
              Delete Account
            </button>
          )}
        </div>
      </div>
    </div>
  );


}
